import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def time_to_reach(point1, point2, speed):
        return euclidean_distance(point1, point2) / speed

    best_node = None
    max_priority_score = -float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        time_to_customer = time_to_reach(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + time_to_customer
        open_time, close_time = time_windows[i]
        penalty = 0
        if arrival_time > close_time:
            penalty += 1e6  # Large penalty for missing the time window
        elif arrival_time < open_time:
            penalty += (open_time - arrival_time)  # Waiting time penalty

        # Calculate priority score: lower penalty, closer proximity, and more free trucks increase the score
        priority_score = (-penalty + 1/(time_to_customer + 1) + 
                          1/((len(all_truck_pos) + 1) * len(unvisited_customers)))

        if priority_score > max_priority_score:
            max_priority_score = priority_score
            best_node = i

    if penalty >= 1e6:
        return None

    return best_node

import numpy as np
import random

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(coord1, coord2):
        return np.linalg.norm(np.array(coord1) - np.array(coord2))

    def calculate_penalty(index):
        _, end_window = time_windows[index]
        return max(0, (current_time + travel_time_to_node[index]) - end_window)

    def effective_time(index):
        start_window, _ = time_windows[index]
        arrive_time = current_time + travel_time_to_node[index]
        if arrive_time < start_window:
            return start_window - current_time
        return 0

    travel_time_to_node = [distance(cur_truck_pos, cust) / truck_speed for cust in unvisited_customers]

    def calculate_cost(index):
        penalty = calculate_penalty(index)
        waiting_time = effective_time(index)
        return travel_time_to_node[index] + penalty + 0.5 * waiting_time

    temperature = 100.0
    cooling_rate = 0.99
    costs = [calculate_cost(i) for i in range(len(unvisited_customers))]
    current_node = random.choice(range(len(unvisited_customers)))
    best_node = current_node

    while temperature > 0.1:
        next_node = (current_node + random.choice([-1, 1])) % len(unvisited_customers)
        cost_diff = costs[next_node] - costs[current_node]
        if cost_diff < 0 or random.uniform(0, 1) < np.exp(-cost_diff / temperature):
            current_node = next_node
            if costs[current_node] < costs[best_node]:
                best_node = current_node
        temperature *= cooling_rate

    return best_node
